import React from 'react';
import Navigation from './components/Navigation';
import Hero from './components/Hero';
import About from './components/About';
import Skills from './components/Skills';
import Projects from './components/Projects';
import Contact from './components/Contact';
import aircraft737 from './assets/737.png';
import aircraft777 from './assets/777.png';
import aircraft787 from './assets/787.png';
import aircraftA350 from './assets/a350.png';
import './styles/App.css';

function App() {
  return (
    <div className="App">
      <div className="tech-grid"></div>
      <div className="aircraft-backgrounds">
        <img src={aircraft737} alt="" className="bg-aircraft bg-aircraft-1" />
        <img src={aircraft777} alt="" className="bg-aircraft bg-aircraft-2" />
        <img src={aircraft787} alt="" className="bg-aircraft bg-aircraft-3" />
        <img src={aircraftA350} alt="" className="bg-aircraft bg-aircraft-4" />
      </div>
      <Navigation />
      <Hero />
      <About />
      <Skills />
      <Projects />
      <Contact />
    </div>
  );
}

export default App;
